
-- Marketplace stats (dynamically configurable)
CREATE TABLE marketplace_stats (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  key text UNIQUE NOT NULL,
  value text NOT NULL,
  label text,
  sort_order int NOT NULL DEFAULT 0,
  updated_at timestamptz DEFAULT now()
);
ALTER TABLE marketplace_stats ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public_read_marketplace_stats" ON marketplace_stats FOR SELECT TO anon, authenticated USING (true);
CREATE POLICY "admin_all_marketplace_stats" ON marketplace_stats FOR ALL TO service_role USING (true) WITH CHECK (true);

-- Marketplace content blocks
CREATE TABLE marketplace_content (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  key text UNIQUE NOT NULL,
  title text,
  body text NOT NULL,
  visible boolean NOT NULL DEFAULT true,
  sort_order int NOT NULL DEFAULT 0,
  updated_at timestamptz DEFAULT now()
);
ALTER TABLE marketplace_content ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public_read_marketplace_content" ON marketplace_content FOR SELECT TO anon, authenticated USING (visible = true);
CREATE POLICY "admin_all_marketplace_content" ON marketplace_content FOR ALL TO service_role USING (true) WITH CHECK (true);

-- Marketplace FAQ (separate from site-wide FAQ)
CREATE TABLE marketplace_faq (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  question text NOT NULL,
  answer text NOT NULL,
  sort_order int NOT NULL DEFAULT 0,
  visible boolean NOT NULL DEFAULT true,
  created_at timestamptz DEFAULT now()
);
ALTER TABLE marketplace_faq ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public_read_marketplace_faq" ON marketplace_faq FOR SELECT TO anon, authenticated USING (visible = true);
CREATE POLICY "admin_all_marketplace_faq" ON marketplace_faq FOR ALL TO service_role USING (true) WITH CHECK (true);

-- Marketplace internal SEO links
CREATE TABLE marketplace_links (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  anchor_text text NOT NULL,
  target_url text NOT NULL,
  description text,
  sort_order int NOT NULL DEFAULT 0,
  visible boolean NOT NULL DEFAULT true
);
ALTER TABLE marketplace_links ENABLE ROW LEVEL SECURITY;
CREATE POLICY "public_read_marketplace_links" ON marketplace_links FOR SELECT TO anon, authenticated USING (visible = true);
CREATE POLICY "admin_all_marketplace_links" ON marketplace_links FOR ALL TO service_role USING (true) WITH CHECK (true);

